mapper.select:
SELECT p.*, c.name AS category_name, a.name AS artisan_name FROM t_product p LEFT JOIN t_category c ON p.category_id = c.id LEFT JOIN t_artisan a ON p.artisan_id = a.id WHERE p.audit_status = 'approved' AND p.is_on_sale = 1
AND p.category_id = #{categoryId}
ORDER BY p.price ASC ORDER BY p.price DESC ORDER BY p.sales DESC ORDER BY p.create_time DESC
LIMIT #{offset}, #{size}

SELECT a.user_id FROM t_product p
JOIN t_artisan a ON p.artisan_id = a.id
WHERE p.id = #{productId}
